159→/// Returns `true` for packages that are infrastructure/library deps and should
160→/// be hidden from the LLM (they're not directly useful as CLI tools).
161→fn is_infrastructure_package(pkg: &str) -> bool {
162→    // lib*-dev, lib* (shared libs), *-dev (header packages), fonts-*
163→    pkg.starts_with("lib")
164→        || pkg.ends_with("-dev")
165→        || pkg.starts_with("fonts-")
166→        // Python dev package
167→        || pkg == "python3-dev"
168→        // Ruby dev package
169→        || pkg == "ruby-dev"
170→        // LLVM dev
171→        || pkg == "llvm-dev"
172→        // Browser automation support libs (not the browser itself)
173→        || pkg.starts_with("libx")
174→        || pkg.starts_with("libn")
175→        || pkg.starts_with("liba")
176→}
