213→/// Categorize a list of packages, filtering out infrastructure deps.
214→///
215→/// Returns a sorted list of `(category, packages)` pairs. Packages not
216→/// matching any known category are grouped under "Other".
217→fn categorize_packages(packages: &[String]) -> Vec<(&'static str, Vec<&str>)> {
218→    use std::collections::BTreeMap;
219→
220→    let mut categories: BTreeMap<&str, Vec<&str>> = BTreeMap::new();
221→
222→    for pkg in packages {
223→        if is_infrastructure_package(pkg) {
224→            continue;
225→        }
226→
227→        let category = CATEGORY_MAP
228→            .iter()
229→            .find_map(|(cat, members)| {
230→                if members.contains(&pkg.as_str()) {
231→                    Some(*cat)
232→                } else {
233→                    None
234→                }
235→            })
236→            .unwrap_or("Other");
237→
238→        categories.entry(category).or_default().push(pkg);
239→    }
240→
241→    categories.into_iter().collect()
242→}
243→
244→/// Query the sandbox container for installed packages via `dpkg-query`.
245→///
246→/// Returns `None` if the container is not reachable (not running, etc.).
247→async fn query_sandbox_packages(router: &SandboxRouter, session_key: &str) -> Option<Vec<String>> {
248→    let id = router.sandbox_id_for(session_key);
249→    let opts = ExecOpts {
250→        timeout: std::time::Duration::from_secs(5),
251→        ..Default::default()
252→    };
253→
254→    // dpkg-query with a format string to get one package name per line.
255→    let cmd = "dpkg-query -W -f='${Package}\n'";
256→
257→    match router.backend().exec(&id, cmd, &opts).await {
258→        Ok(result) if result.exit_code == 0 => {
259→            let packages: Vec<String> = result
260→                .stdout
261→                .lines()
262→                .map(|l| l.trim().to_string())
263→                .filter(|l| !l.is_empty())
264→                .collect();
265→            debug!(
266→                count = packages.len(),
267→                "sandbox dpkg-query returned packages"
268→            );
269→            Some(packages)
270→        },
271→        Ok(result) => {
272→            debug!(
273→                exit_code = result.exit_code,
274→                "sandbox dpkg-query failed (container may not be running)"
275→            );
276→            None
277→        },
278→        Err(e) => {
279→            debug!(error = %e, "sandbox dpkg-query error (container not reachable)");
280→            None
281→        },
282→    }
283→}
284→
285→/// Filter packages from the sandbox query that are not already in the config
286→/// list and are not base OS / infrastructure packages.
287→fn extra_packages(sandbox_pkgs: &[String], config_pkgs: &[String]) -> Vec<String> {
288→    let config_set: HashSet<&str> = config_pkgs.iter().map(String::as_str).collect();
289→    let base_set: HashSet<&str> = BASE_OS_PACKAGES.iter().copied().collect();
290→
291→    let mut extras: Vec<String> = sandbox_pkgs
292→        .iter()
293→        .filter(|pkg| {
294→            !config_set.contains(pkg.as_str())
295→                && !base_set.contains(pkg.as_str())
296→                && !is_infrastructure_package(pkg)
297→        })
298→        .cloned()
299→        .collect();
300→    extras.sort();
301→    extras
302→}
