304→// ── Tool ────────────────────────────────────────────────────────────────────
305→
306→/// LLM-callable tool that lists sandbox packages grouped by category.
307→pub struct SandboxPackagesTool {
308→    sandbox_router: Option<Arc<SandboxRouter>>,
309→}
310→
311→impl SandboxPackagesTool {
312→    pub fn new() -> Self {
313→        Self {
314→            sandbox_router: None,
315→        }
316→    }
317→
318→    /// Attach a sandbox router to read the configured packages.
319→    pub fn with_sandbox_router(mut self, router: Arc<SandboxRouter>) -> Self {
320→        self.sandbox_router = Some(router);
321→        self
322→    }
323→}
324→
325→impl Default for SandboxPackagesTool {
326→    fn default() -> Self {
327→        Self::new()
328→    }
329→}
330→
331→#[async_trait]
332→impl AgentTool for SandboxPackagesTool {
333→    fn name(&self) -> &str {
334→        "sandbox_packages"
335→    }
336→
337→    fn description(&self) -> &str {
338→        "List packages pre-installed in the sandbox container, grouped by category. \
339→         Call this before running commands that need specific tools (image processing, \
340→         audio/video, document conversion, GIS, email, CalDAV, etc.) to check what's \
341→         available. Also reports extra packages installed at runtime if a container is running."
342→    }
343→
344→    fn parameters_schema(&self) -> Value {
345→        json!({
346→            "type": "object",
347→            "properties": {},
348→            "required": [],
349→            "additionalProperties": false
350→        })
351→    }
352→
353→    async fn execute(&self, params: Value) -> anyhow::Result<Value> {
354→        #[cfg(feature = "metrics")]
355→        let start = std::time::Instant::now();
356→
357→        let router = match &self.sandbox_router {
358→            Some(r) => r,
359→            None => {
360→                return Ok(json!({
361→                    "error": "Sandbox is not enabled"
362→                }));
363→            },
364→        };
365→
366→        let packages = &router.config().packages;
367→
368→        if packages.is_empty() {
369→            #[cfg(feature = "metrics")]
370→            {
371→                counter!("tools_sandbox_packages_total").increment(1);
372→                histogram!("tools_sandbox_packages_duration_seconds")
373→                    .record(start.elapsed().as_secs_f64());
374→            }
375→            return Ok(json!({
376→                "total": 0,
377→                "categories": {}
378→            }));
379→        }
380→
381→        // Build categorized config list.
382→        let grouped = categorize_packages(packages);
383→
384→        let mut categories = serde_json::Map::new();
385→        let mut visible_total: usize = 0;
386→        for (category, pkgs) in &grouped {
387→            visible_total += pkgs.len();
388→            categories.insert(
389→                (*category).to_string(),
390→                Value::Array(
391→                    pkgs.iter()
392→                        .map(|p| Value::String((*p).to_string()))
393→                        .collect(),
394→                ),
395→            );
396→        }
397→
398→        let mut result = json!({
399→            "total": visible_total,
400→            "categories": categories
401→        });
402→
403→        // Hybrid: try querying the running sandbox container for extra packages.
404→        let session_key = params
405→            .get("_session_key")
406→            .and_then(|v| v.as_str())
407→            .unwrap_or("main");
408→
409→        if router.is_sandboxed(session_key).await
410→            && let Some(sandbox_pkgs) = query_sandbox_packages(router, session_key).await
411→        {
412→            let extras = extra_packages(&sandbox_pkgs, packages);
413→            if !extras.is_empty() {
414→                result["additional_installed"] = json!(extras);
415→                result["additional_installed_count"] = json!(extras.len());
416→            }
417→        }
418→
419→        #[cfg(feature = "metrics")]
420→        {
421→            counter!("tools_sandbox_packages_total").increment(1);
422→            histogram!("tools_sandbox_packages_duration_seconds")
423→                .record(start.elapsed().as_secs_f64());
424→        }
425→
426→        Ok(result)
427→    }
428→}
