 20→pub(crate) fn truncate_output_for_display(output: &mut String, max_output_bytes: usize) {
 21→    if output.len() <= max_output_bytes {
 22→        return;
 23→    }
 24→    output.truncate(output.floor_char_boundary(max_output_bytes));
 25→    output.push_str("\n... [output truncated]");
 26→}
