 28→/// Return the last `n` lines of `text`, or the full text if it has fewer lines.
 29→pub(crate) fn tail_lines(text: &str, n: usize) -> String {
 30→    let lines: Vec<&str> = text.lines().collect();
 31→    if lines.len() <= n {
 32→        return text.to_string();
 33→    }
 34→    format!(
 35→        "... [{} lines truncated]\n{}",
 36→        lines.len() - n,
 37→        lines[lines.len() - n..].join("\n")
 38→    )
 39→}
