216→impl From<&moltis_config::schema::SandboxConfig> for SandboxConfig {
217→    fn from(cfg: &moltis_config::schema::SandboxConfig) -> Self {
218→        Self {
219→            mode: match cfg.mode.as_str() {
220→                "all" => SandboxMode::All,
221→                "non-main" | "nonmain" => SandboxMode::NonMain,
222→                _ => SandboxMode::Off,
223→            },
224→            scope: match cfg.scope.as_str() {
225→                "agent" => SandboxScope::Agent,
226→                "shared" => SandboxScope::Shared,
227→                _ => SandboxScope::Session,
228→            },
229→            workspace_mount: match cfg.workspace_mount.as_str() {
230→                "rw" => WorkspaceMount::Rw,
231→                "none" => WorkspaceMount::None,
232→                _ => WorkspaceMount::Ro,
233→            },
234→            host_data_dir: cfg
235→                .host_data_dir
236→                .as_deref()
237→                .map(str::trim)
238→                .filter(|p| !p.is_empty())
239→                .map(PathBuf::from),
240→            home_persistence: HomePersistence::from(&cfg.home_persistence),
241→            shared_home_dir: cfg
242→                .shared_home_dir
243→                .as_deref()
244→                .map(str::trim)
245→                .filter(|p| !p.is_empty())
246→                .map(PathBuf::from),
247→            image: cfg.image.clone(),
248→            container_prefix: cfg.container_prefix.clone(),
249→            no_network: cfg.no_network,
250→            network: match cfg.network.as_str() {
251→                "trusted" => NetworkPolicy::Trusted,
252→                "bypass" => NetworkPolicy::Bypass,
253→                // Explicit "blocked" always means Blocked.
254→                "blocked" => NetworkPolicy::Blocked,
255→                // Empty/unset: fall back to legacy `no_network` flag.
256→                _ if cfg.no_network => NetworkPolicy::Blocked,
257→                _ => NetworkPolicy::Trusted,
258→            },
259→            trusted_domains: cfg.trusted_domains.clone(),
260→            backend: cfg.backend.clone(),
261→            resource_limits: ResourceLimits {
262→                memory_limit: cfg.resource_limits.memory_limit.clone(),
263→                cpu_quota: cfg.resource_limits.cpu_quota,
264→                pids_max: cfg.resource_limits.pids_max,
265→            },
266→            packages: cfg.packages.clone(),
267→            timezone: None, // Set by gateway from user profile
268→            wasm_fuel_limit: cfg.wasm_fuel_limit,
269→            wasm_epoch_interval_ms: cfg.wasm_epoch_interval_ms,
270→            wasm_tool_limits: cfg.wasm_tool_limits.as_ref().map(WasmToolLimits::from),
271→        }
272→    }
273→}
